import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

function WorkerManagement() {

const today = new Date().toISOString().split("T")[0];

const [workers, setWorkers] = useState([]);
const [projects, setProjects] = useState([]);
const [showForm, setShowForm] = useState(false);
const [editId, setEditId] = useState(null);

const emptyForm = {
name: "",
phone: "",
email: "",
role: "",
project: "",
experience: "",
address: "",
currentStatus: "Available",
joined: today,

category: "Worker",
wageType: "Daily",
dailyWage: "",
monthlyWage: "",
skillType: "",
salary: ""
};

const [formData, setFormData] = useState(emptyForm);


// ================= FETCH WORKERS (SOURCE OF TRUTH)
const loadWorkers = async () => {
try {
const res = await fetch("http://localhost:5000/api/workers");
const data = await res.json();

if (Array.isArray(data)) setWorkers(data);
else if (Array.isArray(data?.data)) setWorkers(data.data);
else setWorkers([]);
} catch (err) {
console.error("Worker fetch error:", err);
setWorkers([]);
}
};


// ================= FETCH PROJECTS
const loadProjects = async () => {
try {
const res = await fetch("http://localhost:5000/api/projects");
const data = await res.json();
setProjects(Array.isArray(data) ? data : []);
} catch (err) {
console.error(err);
}
};


// ================= INITIAL LOAD
useEffect(() => {
loadWorkers();
loadProjects();
}, []);


// ================= HANDLE CHANGE
const handleChange = (e) => {
const { name, value } = e.target;

if (name === "name" && !/^[A-Za-z\s]*$/.test(value)) return;
if (name === "phone" && !/^\d{0,10}$/.test(value)) return;
if (name === "address" && !/^[A-Za-z0-9\s]*$/.test(value)) return;
if (name === "experience" && (value < 0 || value > 20)) return;

if (name === "email") {
if ((value.match(/@/g) || []).length > 1) return;
}

if (["salary", "dailyWage", "monthlyWage"].includes(name)) {
if (value < 0) return;
}

if (name === "skillType") {
setFormData(prev => ({
...prev,
skillType: value,
role: value
}));
return;
}

setFormData(prev => ({ ...prev, [name]: value }));
};


// ================= SUBMIT (IMPORTANT FIX HERE)
const handleSubmit = async (e) => {
e.preventDefault();

try {

const url = editId
? `http://localhost:5000/api/workers/${editId}`
: "http://localhost:5000/api/workers";

const method = editId ? "PUT" : "POST";

await fetch(url, {
method,
headers: { "Content-Type": "application/json" },
body: JSON.stringify({
...formData,
assigned_project: formData.project,
current_status: formData.currentStatus,
wage_type: formData.wageType,
daily_wage: formData.dailyWage,
monthly_wage: formData.monthlyWage,
skill_type: formData.skillType
})
});

// 🔥 IMPORTANT: ALWAYS RELOAD FROM SERVER
await loadWorkers();

setFormData(emptyForm);
setShowForm(false);
setEditId(null);

} catch (err) {
console.error(err);
alert("Save failed");
}
};


// ================= DELETE
const handleDelete = async (id) => {
if (!window.confirm("Delete worker?")) return;

try {
await fetch(`http://localhost:5000/api/workers/${id}`, {
method: "DELETE"
});

// reload fresh list
await loadWorkers();

} catch (err) {
console.error(err);
}
};


// ================= EDIT
const handleEdit = (w) => {
setFormData({
name: w.name || "",
phone: w.phone || "",
email: w.email || "",
role: w.role || "",
project: w.assigned_project || "",
experience: w.experience || "",
address: w.address || "",
currentStatus: w.current_status || "Available",
joined: w.joined || today,

category: w.category || "Worker",
wageType: w.wage_type || "Daily",
dailyWage: w.daily_wage || "",
monthlyWage: w.monthly_wage || "",
skillType: w.skill_type || "",
salary: w.salary || ""
});

setEditId(w.id || w._id);
setShowForm(true);
};


// ================= UI
return (
<div className="flex bg-gray-100 min-h-screen">
<Sidebar />

<div className="flex-1 p-6">
<Topbar />

{showForm ? (

<div className="bg-white p-6 rounded shadow mt-6">
<h2 className="text-xl font-bold mb-4">
{editId ? "Edit Worker" : "Add Worker"}
</h2>

<form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">

<input name="name" placeholder="Name" value={formData.name} onChange={handleChange} className="border p-2"/>
<input name="phone" placeholder="Phone" value={formData.phone} onChange={handleChange} className="border p-2"/>
<input name="email" placeholder="Email" value={formData.email} onChange={handleChange} className="border p-2"/>

<select name="category" value={formData.category} onChange={handleChange} className="border p-2">
<option>Worker</option>
<option>Employee</option>
</select>

<select name="skillType" value={formData.skillType} onChange={handleChange} className="border p-2">
<option value="">Select Skill</option>
<option>Carpenter</option>
<option>Electrician</option>
<option>Plumber</option>
<option>Mason</option>
</select>

<button className="bg-green-500 text-white p-2 col-span-2">Save</button>

</form>
</div>

) : (

<>
<div className="flex justify-between mt-6">
<h1 className="text-2xl font-bold">Workers</h1>
<button onClick={() => setShowForm(true)} className="bg-orange-500 text-white px-4 py-2 rounded">
+ Add
</button>
</div>

<table className="w-full mt-4 bg-white shadow">
<thead>
<tr>
<th>Name</th>
<th>Phone</th>
<th>Type</th>
<th>Skill</th>
<th>Action</th>
</tr>
</thead>

<tbody>
{workers.map(w => (
<tr key={w.id || w._id}>
<td>{w.name}</td>
<td>{w.phone}</td>
<td>{w.category}</td>
<td>{w.skill_type}</td>
<td>
<button onClick={() => handleEdit(w)}>Edit</button>
<button onClick={() => handleDelete(w.id || w._id)}>Delete</button>
</td>
</tr>
))}
</tbody>
</table>
</>
)}

</div>
</div>
);
}

export default WorkerManagement;
